"""
Pytest tests for savings account daily interest accrual and monthly crediting.

Requirement: A savings account shall accrue interest daily using the tier rate
and credit interest monthly on the last business day. Boundary behaviour at
exact min/max thresholds must be tested.
"""

import pytest
from decimal import Decimal, ROUND_HALF_UP
from datetime import date, datetime
from unittest.mock import MagicMock, patch, call
import calendar


# ---------------------------------------------------------------------------
# Domain model assumed under test
# ---------------------------------------------------------------------------
# from savings.account import SavingsAccount
# from savings.interest_engine import InterestEngine
# from savings.rate_tiers import RateTier, RateTierSchedule
# from savings.calendar_utils import BusinessCalendar
#
# The stubs below let the test file be self-contained and make the
# expected interface explicit.
# ---------------------------------------------------------------------------

# ── Stub implementations (replace with real imports) ──────────────────────


class RateTier:
    """Defines an inclusive balance range and its annual interest rate."""

    def __init__(
        self,
        min_balance: Decimal,
        max_balance: Decimal | None,  # None == unbounded
        annual_rate: Decimal,
        tier_label: str = "",
    ):
        if min_balance < Decimal("0"):
            raise ValueError("min_balance must be >= 0")
        if max_balance is not None and max_balance < min_balance:
            raise ValueError("max_balance must be >= min_balance")
        self.min_balance = min_balance
        self.max_balance = max_balance
        self.annual_rate = annual_rate
        self.tier_label = tier_label

    def contains(self, balance: Decimal) -> bool:
        if balance < self.min_balance:
            return False
        if self.max_balance is not None and balance > self.max_balance:
            return False
        return True


class RateTierSchedule:
    """Ordered collection of RateTiers; resolves the correct tier for a balance."""

    def __init__(self, tiers: list[RateTier]):
        # Validate no gaps / overlaps (simplified)
        self._tiers = sorted(tiers, key=lambda t: t.min_balance)

    def rate_for_balance(self, balance: Decimal) -> Decimal:
        for tier in self._tiers:
            if tier.contains(balance):
                return tier.annual_rate
        raise ValueError(f"No tier found for balance {balance}")

    def tier_for_balance(self, balance: Decimal) -> RateTier:
        for tier in self._tiers:
            if tier.contains(balance):
                return tier
        raise ValueError(f"No tier found for balance {balance}")


class BusinessCalendar:
    """Determines business days (Mon–Fri, no holidays for simplicity)."""

    def __init__(self, holidays: list[date] | None = None):
        self._holidays = set(holidays or [])

    def is_business_day(self, d: date) -> bool:
        return d.weekday() < 5 and d not in self._holidays

    def last_business_day_of_month(self, year: int, month: int) -> date:
        last_day = calendar.monthrange(year, month)[1]
        candidate = date(year, month, last_day)
        while not self.is_business_day(candidate):
            candidate = date(candidate.year, candidate.month, candidate.day - 1)
        return candidate


class SavingsAccount:
    """Core savings account with daily accrual and monthly crediting."""

    DAYS_IN_YEAR = Decimal("365")

    def __init__(
        self,
        account_id: str,
        opening_balance: Decimal,
        tier_schedule: RateTierSchedule,
        business_calendar: BusinessCalendar,
        opened_date: date,
    ):
        self.account_id = account_id
        self._balance = opening_balance
        self._accrued_interest = Decimal("0")
        self._tier_schedule = tier_schedule
        self._calendar = business_calendar
        self._opened_date = opened_date
        self._last_credited_date: date | None = None
        self._interest_history: list[dict] = []

    # ── properties ────────────────────────────────────────────────────────

    @property
    def balance(self) -> Decimal:
        return self._balance

    @property
    def accrued_interest(self) -> Decimal:
        return self._accrued_interest

    @property
    def last_credited_date(self) -> date | None:
        return self._last_credited_date

    @property
    def interest_history(self) -> list[dict]:
        return list(self._interest_history)

    # ── public methods ────────────────────────────────────────────────────

    def accrue_daily_interest(self, as_of_date: date) -> Decimal:
        """
        Calculate and accumulate one day's interest for *as_of_date*.
        Returns the daily interest amount added.
        """
        annual_rate = self._tier_schedule.rate_for_balance(self._balance)
        daily_interest = (
            self._balance * annual_rate / self.DAYS_IN_YEAR
        ).quantize(Decimal("0.0000001"), rounding=ROUND_HALF_UP)
        self._accrued_interest += daily_interest
        return daily_interest

    def credit_monthly_interest(self, credit_date: date) -> Decimal:
        """
        Credit all accrued interest to balance on *credit_date*.
        Raises ValueError if credit_date is not the last business day of its month.
        Returns the amount credited.
        """
        lbd = self._calendar.last_business_day_of_month(
            credit_date.year, credit_date.month
        )
        if credit_date != lbd:
            raise ValueError(
                f"{credit_date} is not the last business day of "
                f"{credit_date.year}-{credit_date.month:02d} (expected {lbd})"
            )
        credited = self._accrued_interest
        self._balance += credited
        self._accrued_interest = Decimal("0")
        self._last_credited_date = credit_date
        self._interest_history.append(
            {
                "date": credit_date,
                "amount": credited,
                "balance_after": self._balance,
            }
        )
        return credited

    def process_month(self, year: int, month: int) -> dict:
        """
        Convenience: accrue every day then credit on the last business day.
        Returns a summary dict.
        """
        last_day = calendar.monthrange(year, month)[1]
        total_accrued = Decimal("0")
        for day in range(1, last_day + 1):
            d = date(year, month, day)
            total_accrued += self.accrue_daily_interest(d)
        lbd = self._calendar.last_business_day_of_month(year, month)
        credited = self.credit_monthly_interest(lbd)
        return {
            "year": year,
            "month": month,
            "days_accrued": last_day,
            "total_accrued": total_accrued,
            "credited": credited,
            "credit_date": lbd,
            "closing_balance": self._balance,
        }


