class TestRateTierResolution:
    """Unit tests: correct tier / rate selected for a given balance."""

    # ── well-within-tier balances ─────────────────────────────────────────

    @pytest.mark.parametrize(
        "balance_str, expected_rate_str, description",
        [
            ("500.00",     "0.0100", "mid Tier-1"),
            ("2500.00",    "0.0150", "mid Tier-2"),
            ("10000.00",   "0.0200", "mid Tier-3"),
            ("50000.00",   "0.0250", "mid Tier-4"),
            ("200000.00",  "0.0300", "mid Tier-5 (unbounded)"),
        ],
    )
    def test_rate_resolved_for_mid_tier_balance(
        self, balance_str, expected_rate_str, description, tier_schedule
    ):
        rate = tier_schedule.rate_for_balance(Decimal(balance_str))
        assert rate == Decimal(expected_rate_str), description

    # ── exact minimum thresholds ──────────────────────────────────────────

    @pytest.mark.parametrize(
        "balance_str, expected_rate_str",
        [
            ("0.00",      "0.0100"),   # absolute minimum (Tier-1 floor)
            ("1000.00",   "0.0150"),   # exact Tier-2 lower bound
            ("5000.00",   "0.0200"),   # exact Tier-3 lower bound
            ("25000.00",  "0.0250"),   # exact Tier-4 lower bound
            ("100000.00", "0.0300"),   # exact Tier-5 lower bound
        ],
    )
    def test_rate_at_exact_tier_minimum(
        self, balance_str, expected_rate_str, tier_schedule
    ):
        rate = tier_schedule.rate_for_balance(Decimal(balance_str))
        assert rate == Decimal(expected_rate_str), (
            f"Balance {balance_str} must resolve to rate {expected_rate_str}"
        )

    # ── exact maximum thresholds ──────────────────────────────────────────

    @pytest.mark.parametrize(
        "balance_str, expected_rate_str",
        [
            ("999.99",   "0.0100"),   # exact Tier-1 upper bound
            ("4999.99",  "0.0150"),   # exact Tier-2 upper bound
            ("24999.99", "0.0200"),   # exact Tier-3 upper bound
            ("99999.99", "0.0250"),   # exact Tier-4 upper bound
        ],
    )
    def test_rate_at_exact_tier_maximum(
        self, balance_str, expected_rate_str, tier_schedule
    ):
        rate = tier_schedule.rate_for_balance(Decimal(balance_str))
        assert rate == Decimal(expected_rate_str), (
            f"Balance {balance_str} must resolve to rate {expected_rate_str}"
        )

    # ── one-cent above/below boundary (cross-tier) ────────────────────────

    @pytest.mark.parametrize(
        "below_str, below_rate, above_str, above_rate, boundary_label",
        [
            ("999.99",  "0.0100", "1000.00", "0.0150", "Tier1/Tier2 boundary"),
            ("4999.99", "0.0150", "5000.00", "0.0200", "Tier2/Tier3 boundary"),
            ("24999.99","0.0200", "25000.00","0.0250", "Tier3/Tier4 boundary"),
            ("99999.99","0.0250","100000.00","0.0300", "Tier4/Tier5 boundary"),
        ],
    )
    def test_cross_tier_boundary_one_cent(
        self,
        below_str, below_rate,
        above_str, above_rate,
        boundary_label,
        tier_schedule,
    ):
        assert tier_schedule.rate_for_balance(Decimal(below_str)) == Decimal(
            below_rate
        ), f"{boundary_label}: balance just below should use lower tier"
        assert tier_schedule.rate_for_balance(Decimal(above_str)) == Decimal(
            above_rate
        ), f"{boundary_label}: balance at lower bound should use higher tier"

    def test_negative_balance_raises(self, tier_schedule):
        with pytest.raises((ValueError, KeyError)):
            tier_schedule.rate_for_balance(Decimal("-0.01"))

    def test_zero_balance_resolves_to_tier1(self, tier_schedule):
        tier = tier_schedule.tier_for_balance(Decimal("0.00"))
        assert tier.tier_label == "Tier 1"


class TestDailyInterestAccrual:
    """Unit tests: daily interest calculated and accumulated correctly."""

    def test_daily_interest_uses_365_day_convention(
        self, tier_schedule, biz_calendar
    ):
        balance = Decimal("10000.00")
        annual_rate = Decimal("0.0200")  # Tier-3
        expected_daily = (
            balance * annual_rate / Decimal("365")
        ).quantize(Decimal("0.0000001"), rounding=ROUND_HALF_UP)

        account = make_account("10000.00", tier_schedule, biz_calendar)
        daily = account.accrue_daily_interest(date(2024, 3, 15))

        assert daily == expected_daily

    def test_accrued_interest_accumulates_over_multiple_days(
        self, tier_schedule, biz_calendar
    ):
        account = make_account("5000.00", tier_schedule, biz_calendar)
        days = [date(2024, 6, d) for d in range(1, 6)]  # 5 days
        total = sum(account.accrue_daily_interest(d) for d in days)

        assert account.accrued_interest == pytest.approx(
            float(total), rel=1e-9
        )

    def test_accrual_does_not_alter_principal_balance(
        self, tier_schedule, biz_calendar
    ):
        opening = Decimal("2000.00")
        account = make_account("2000.00", tier_schedule, biz_calendar)
        for day in range(1, 32):  # full month
            account.accrue_daily_interest(date(2024, 1, day))

        assert account.balance == opening

    def test_daily_interest_is_non_zero_for_positive_balance(
        self, tier_schedule, biz_calendar
    ):
        account = make_account("1.00", tier_schedule, biz_calendar)
        daily = account.accrue_daily_interest(date(2024, 1, 1))
        assert daily > Decimal("0")

    def test_daily_interest_is_zero_for_zero_balance(
        self, tier_schedule, biz_calendar
    ):
        account = make_account("0.00", tier_schedule, biz_calendar)
        daily = account.accrue_daily_interest(date(2024, 1, 1))
        assert daily == Decimal("0")

    @pytest.mark.parametrize(
        "balance_str, expected_tier_rate",
        [
            ("999.99",    "0.0100"),
            ("1000.00",   "0.0150"),
            ("4999.99",   "0.0150"),
            ("5000.00",   "0.0200"),
            ("24999.99",  "0.0200"),
            ("25000.00",  "0.0250"),
            ("99999.99",  "0.0250"),
            ("100000.00", "0.0300"),
        ],
    )
    def test_daily_interest_reflects_correct_tier_rate_at_boundary(
        self, balance_str, expected_tier_rate, tier_schedule, biz_calendar
    ):
        balance = Decimal(balance_str)
        rate = Decimal(expected_tier_rate)
        expected = (balance * rate / Decimal("365")).quantize(
            Decimal("0.0000001"), rounding=ROUND_HALF_UP
        )
        account = make_account(balance_str, tier_schedule, biz_calendar)
        daily = account.accrue_daily_interest(date(2024, 5, 1))
        assert daily == expected, (
            f"Balance {balance_str}: expected daily {expected}, got {daily}"
        )

    def test_accrual_called_once_per_day_produces_consistent_result(
        self, tier_schedule, biz_calendar
    ):
        account1 = make_account("3000.00", tier_schedule, biz_calendar)
        account2 = make_account("3000.00", tier_schedule, biz_calendar)
        d = date(2024, 7, 15)

        r1 = account1.accrue_daily_interest(d)
        r2 = account2.accrue_daily_interest(d)

        assert r1 == r2  # deterministic / idempotent per call

    def test_daily_interest_precision_is_at_least_seven_decimal_places(
        self, tier_schedule, biz_calendar
    ):
        """Interest must be held to ≥7 d.p. to avoid large cumulative error."""
        account = make_account("1.00", tier_schedule, biz_calendar)
        daily = account.accrue_daily_interest(date(2024, 1, 1))
        # Decimal('0.0000000') has exponent -7; daily should be similarly precise
        assert daily.as_tuple().exponent <= -7


class TestLastBusinessDayCalculation:
    """Unit tests: last-business-day-of-month logic."""

    @pytest.mark.parametrize(
        "year, month, expected_day",
        [
            # Standard months ending on Mon–Fri
            (2024, 1, 31),  # Wednesday
            (2024, 3, 29),  # Friday (31st is Sunday → roll back)
            (2024, 5, 31),  # Friday
            (2024, 8, 30),  # Friday (31st is Saturday → roll back)
            (2024, 9, 30),  # Monday
            (2024, 10, 31), # Thursday
            (2024, 11, 29), # Friday (30th is Saturday → roll back)
            (2024, 12, 31), # Tuesday
        ],
    )
    def test_last_business_day_standard(
        self, year, month, expected_day, biz_calendar
    ):
        result = biz_calendar.last_business_day_of_month(year, month)
        assert result == date(year, month, expected_day), (
            f"{year}-{month:02d}: expected day {expected_day}, got {result.day}"
        )

    def test_last_business_day_with_holiday_on_last_friday(
        self, biz_calendar_with_holidays
    ):
        # Dec 2024: 31st is Tuesday (not a holiday) → still the 31st
        result = biz_calendar_with_holidays.last_business_day_of_month(2024, 12)
        assert result == date(2024, 12, 31)

    def test_last_business_day_respects_holiday_list(self):
        # Make Dec 31 2024 a holiday; next candidate is Dec 30 (Monday)
        cal = BusinessCalendar(holidays=[date(2024, 12, 31)])
        result = cal.last_business_day_of_month(2024, 12)
        assert result == date(2024, 12, 30)

    def test_last_business_day_february_non_leap_year(self, biz_calendar):
        # Feb 2025: 28th is a Friday
        result = biz_calendar.last_business_day_of_month(2025, 2)
        assert result == date(2025, 2, 28)

    def test_last_business_day_february_leap_year(self, biz_calendar):
        # Feb 2028: 29th is a Tuesday
        result = biz_calendar.last_business_day_of_month(2028, 2)
        assert result == date(2028, 2, 29)

    @pytest.mark.parametrize("weekday", [5, 6])  # Saturday=5, Sunday=6
    def test_last_business_day_never_falls_on_weekend(
        self, weekday, biz_calendar
    ):
        for month in range(1, 13):
            lbd = biz_calendar.last_business_day_of_month(2024, month)
            assert lbd.weekday() < 5, (
                f"{lbd} is a weekend day for month {month}"
            )


class TestMonthlyCreditingOnLastBusinessDay:
    """Unit tests: interest is credited on the correct date."""

    def test_credit_on_last_business_day_succeeds(
        self, tier_schedule, biz_calendar
    ):
        account = make_account("5000.00", tier_schedule, biz_calendar)
        # Accrue January 2024 (31 days)
        for day in range(1, 32):
            account.accrue_daily_interest(date(2024, 1, day))
        accrued = account.accrued_interest

        credited = account.credit_monthly_interest(date(2024, 1, 31))  # Wed

        assert credited == accrued
        assert account.accrued_interest == Decimal("0")

    def test_credit_on_non_last_business_day_raises(
        self, tier_schedule, biz_calendar
    ):
        account = make_account("5000.00", tier_schedule, biz_calendar)
        account.accrue_daily_interest(date(2024, 1, 15))

        with pytest.raises(ValueError, match="not the last business day"):
            account.credit_monthly_interest(date(2024, 1, 15))

    def test_credit_on_weekend_raises(self, tier_schedule, biz_calendar):
        account = make_account("1000.00", tier_schedule, biz_calendar)
        account.accrue_daily_interest(date(2024, 3, 30))  # Saturday

        with pytest.raises(ValueError):
            account.credit_monthly_interest(date(2024, 3, 30))

    def test_accrued_interest_resets_to_zero_after_credit(
        self, tier_schedule, biz_calendar
    ):
        account = make_account("2000.00", tier_schedule, biz_calendar)
        for day in range(1, 30):
            account.accrue_daily_interest(date(2024, 4, day))
        account.credit_monthly_interest(date(2024, 4, 30))  # Tuesday

        assert account.accrued_interest == Decimal("0")

    def test_balance_increases_by_credited_amount(
        self, tier_schedule, biz_calendar
    ):
        opening = Decimal("10000.00")
        account = make_account("10000.00", tier_schedule, biz_calendar)
        for day in range(1, 32):
            account.accrue_daily_interest(date(2024, 5, day))
        accrued = account.accrued_interest
        account.credit_monthly_interest(date(2024, 5, 31))  # Friday

        assert account.balance == opening + accrued

    def test_last_credited_date_updated_after_credit(
        self, tier_schedule, biz_calendar
    ):
        account = make_account("3000.00", tier_schedule, biz_calendar)
        for day in range(1, 32):
            account.accrue_daily_interest(date(2024, 1, day))
        account.credit_monthly_interest(date(2024, 1, 31))

        assert account.last_credited_date == date(2024, 1, 31)

    def test_interest_history_records_credit_event(
        self, tier_schedule, biz_calendar
    ):
        account = make_account("5000.00", tier_schedule, biz_calendar)
        for day in range(1, 30):
            account.accrue_daily_interest(date(2024, 4, day))
        account.credit_monthly_interest(date(2024, 4, 30))

        history = account.interest_history
        assert len(history) == 1
        assert history[0]["date"] == date(2024, 4, 30)
        assert history[0]["amount"] > Decimal("0")

    def test_multiple_months_history_recorded(
        self, tier_schedule, biz_calendar
    ):
        account = make_account("5000.00", tier_schedule, biz_calendar)
        months = [(2024, 1, 31), (2024, 2, 29), (2024, 3, 29)]
        for year, month, lbd_day in months:
            last_day = calendar.monthrange(year, month)[1]
            for day in range(1, last_day + 1):
                account.accrue_daily_interest(date(year, month, day))
            account.credit_monthly_interest(date(year, month, lbd_day))

        assert len(account.interest_history) == 3


class TestProcessMonthIntegration:
    """Integration tests: full month processing pipeline."""

    def test_process_january_2024(self, tier_schedule, biz_calendar):
        account = make_account("10000.00", tier_schedule, biz_calendar)
        result = account.process_month(2024, 1)

        assert result["days_accrued"] == 31
        assert result["credit_date"] == date(2024, 1, 31)
        assert result["credited"] > Decimal("0")
        assert result["closing_balance"] > Decimal("10000.00")

    def test_process_february_2024_leap_year(self, tier_schedule, biz_calendar):
        account = make_account("5000.00", tier_schedule, biz_calendar)
        result = account.process_month(2024, 2)

        # 2024 is a leap year → 29 days; Feb 29 is Thursday → last biz day
        assert result["days_accrued"] == 29
        assert result["credit_date"] == date(2024, 2, 29)

    def test_process_month_credit_equals_sum_of_daily_accruals(
        self, tier_schedule, biz_calendar
    ):
        account = make_account("25000.00", tier_schedule, biz_calendar)
        result = account.process_month(2024, 6)

        # All 30 days accrued must equal the credited amount (no rounding loss)
        assert result["total_accrued"] == result["credited"]

    def test_credited_interest_compounds_into_next_month(
        self, tier_schedule, biz_calendar
    ):
        account = make_account("4999.99", tier_schedule, biz_calendar)
        # After crediting, balance may cross into Tier-3
        result_jan = account.process_month(2024, 1)
        balance_after_jan = result_jan["closing_balance"]

        result_feb = account.process_month(2024, 2)

        # If balance crossed 5000 after January, February uses Tier-3 rate
        if balance_after_jan >= Decimal("5000.00"):
            expected_rate = Decimal("0.0200")
        else:
            expected_rate = Decimal("0.0150")

        daily_rate = tier_schedule.rate_for_balance(balance_after_jan)
        assert daily_rate == expected_rate

        # February credited must be greater than zero
        assert result_feb["credited"] > Decimal("0")

    @pytest.mark.parametrize("balance_str", ["999.99", "1000.00", "4999.99",
                                              "5000.00", "24999.99", "25000.00",
                                              "99999.99", "100000.00"])
    def test_boundary_balance_accrues_correct_monthly_total(
        self, balance_str, tier_schedule, biz_calendar
    ):
        balance = Decimal(balance_str)
